-- DispoTrack — Seed Transactions & Assets
-- Run in Supabase SQL Editor
-- Creates 10 transactions across existing clients with ~60 assets total.
-- internal_asset_id is auto-generated by trigger — do NOT provide it.
-- Also creates inventory records + journal entries to match the intake workflow.
-- Transaction numbers use .99xxx sequences to avoid conflicts with app-created data.

-- ============================================================================
-- CLEANUP (idempotent — safe to re-run)
-- ============================================================================

-- Delete in dependency order (children first)
DELETE FROM inventory_journal WHERE asset_id IN (SELECT id FROM assets WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%');
DELETE FROM inventory WHERE asset_id IN (SELECT id FROM assets WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%');
DELETE FROM asset_status_history WHERE asset_id IN (SELECT id FROM assets WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%');
DELETE FROM asset_sanitization WHERE asset_id IN (SELECT id FROM assets WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%');
DELETE FROM asset_grading WHERE asset_id IN (SELECT id FROM assets WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%');
DELETE FROM asset_hard_drives WHERE asset_id IN (SELECT id FROM assets WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%');
DELETE FROM asset_sales WHERE asset_id IN (SELECT id FROM assets WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%');
DELETE FROM assets WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%';
DELETE FROM transactions WHERE id::text LIKE 'a0000001-0001-4000-8000-0000000000%';

-- ============================================================================
-- TRANSACTIONS (10)
-- ============================================================================

