-- ============================================================================
-- INVENTORY & JOURNAL (one per asset, matching intake workflow)
-- ============================================================================

-- Create inventory records for all 72 assets at RECEIVING location
INSERT INTO public.inventory (asset_id, location, quantity_on_hand, unit_of_measure, status)
SELECT id, 'RECEIVING', quantity, COALESCE(unit_of_measure, 'EA'),
  CASE
    WHEN status = 'available' THEN 'available'
    WHEN status = 'recycled' THEN 'available'
    ELSE 'in_process'
  END
FROM public.assets
WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%';

-- Create journal receipt entries for all assets
INSERT INTO public.inventory_journal (inventory_id, asset_id, transaction_id, movement_type, quantity, to_location, reference_number, reason)
SELECT i.id, a.id, a.transaction_id, 'receipt', a.quantity, 'RECEIVING',
  (SELECT t.transaction_number FROM transactions t WHERE t.id = a.transaction_id),
  'Initial receipt at intake'
FROM public.assets a
JOIN public.inventory i ON i.asset_id = a.id
WHERE a.id::text LIKE 'b0000001-0001-4000-8000-0000000000%';


-- ============================================================================
-- STATUS HISTORY (initial "received" entry for all, plus progression for others)
-- ============================================================================

-- All assets get a "received" history entry
INSERT INTO public.asset_status_history (asset_id, previous_status, new_status, reason_for_change)
SELECT id, NULL, 'received', 'Initial intake'
FROM public.assets
WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%';

-- Assets that progressed beyond "received" — add additional history
INSERT INTO public.asset_status_history (asset_id, previous_status, new_status, reason_for_change)
SELECT id, 'received', 'in_process', 'Moved to processing'
FROM public.assets
WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%'
  AND status IN ('in_process', 'tested', 'graded', 'sanitized', 'available', 'sold', 'recycled');

INSERT INTO public.asset_status_history (asset_id, previous_status, new_status, reason_for_change)
SELECT id, 'in_process', 'tested', 'Testing complete'
FROM public.assets
WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%'
  AND status IN ('tested', 'graded', 'sanitized', 'available', 'sold', 'recycled');

INSERT INTO public.asset_status_history (asset_id, previous_status, new_status, reason_for_change)
SELECT id, 'tested', 'graded', 'Grading complete'
FROM public.assets
WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%'
  AND status IN ('graded', 'sanitized', 'available', 'sold', 'recycled');

INSERT INTO public.asset_status_history (asset_id, previous_status, new_status, reason_for_change)
SELECT id, 'graded', 'sanitized', 'Sanitization complete'
FROM public.assets
WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%'
  AND status IN ('sanitized', 'available', 'sold', 'recycled');

INSERT INTO public.asset_status_history (asset_id, previous_status, new_status, reason_for_change)
SELECT id, 'sanitized', 'available', 'Available for disposition'
FROM public.assets
WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%'
  AND status IN ('available', 'sold');

INSERT INTO public.asset_status_history (asset_id, previous_status, new_status, reason_for_change)
SELECT id, 'graded', 'recycled', 'Marked for recycling — not repairable'
FROM public.assets
WHERE id::text LIKE 'b0000001-0001-4000-8000-0000000000%'
  AND status = 'recycled';
